  9→export default function TrussDetailRenderer({ trussSystem, trussInstanceId = null, showTitle = true }) {
 10→  const scene = buildTrussDetailScene(trussSystem, trussInstanceId);
 11→  if (!scene) {
 12→    return (
 13→      <g className="truss-detail-empty">
 14→        <text
 15→          x={0}
 16→          y={0}
 17→          textAnchor="middle"
 18→          dominantBaseline="middle"
 19→          fill="var(--color-text-secondary)"
 20→          fontSize={180}
 21→          fontFamily="var(--font-blueprint)"
 22→        >
 23→          Add a truss instance to view its detail.
 24→        </text>
 25→      </g>
 26→    );
 27→  }
 28→
 29→  const titleX = (scene.bounds.minX + scene.bounds.maxX) / 2;
 30→  const titleY = -scene.bounds.maxZ + 260;
 31→  const profile = scene.instanceGeometry;
 32→
 33→  return (
 34→    <g className="truss-detail">
 35→      {showTitle && (
 36→        <text
 37→          x={titleX}
 38→          y={titleY}
 39→          textAnchor="middle"
 40→          dominantBaseline="middle"
 41→          fill={DRAWING_GRAPHICS.annotation.textMuted}
 42→          fontSize={180}
 43→          fontFamily="var(--font-blueprint)"
 44→        >
 45→          {scene.title}
 46→        </text>
 47→      )}
 48→      <polyline
 49→        points={profile.roofOutline.map(pointString).join(' ')}
 50→        fill="none"
 51→        stroke={DRAWING_GRAPHICS.section.cutStroke}
 52→        strokeWidth={1.8}
 53→        vectorEffect="non-scaling-stroke"
 54→      />
 55→      <polyline
 56→        points={profile.bottomOutline.map(pointString).join(' ')}
 57→        fill="none"
 58→        stroke={DRAWING_GRAPHICS.section.cutStroke}
 59→        strokeWidth={1.3}
 60→        vectorEffect="non-scaling-stroke"
 61→      />
 62→      {scene.lineSegments.map((segment) => (
 63→        <line
 64→          key={segment.id}
 65→          x1={segment.start.x}
 66→          y1={-segment.start.z}
 67→          x2={segment.end.x}
 68→          y2={-segment.end.z}
 69→          stroke={segment.memberType === 'web'
 70→            ? DRAWING_GRAPHICS.section.projectionStroke
 71→            : DRAWING_GRAPHICS.section.cutStroke}
 72→          strokeWidth={segment.memberType === 'web' ? 0.95 : 1.45}
 73→          vectorEffect="non-scaling-stroke"
 74→        />
 75→      ))}
 76→      {(scene.purlinMarkers || []).map((marker) => (
 77→        <line
 78→          key={marker.id}
 79→          x1={marker.start.x}
 80→          y1={-marker.start.z}
 81→          x2={marker.end.x}
 82→          y2={-marker.end.z}
 83→          stroke={DRAWING_GRAPHICS.section.projectionStroke}
 84→          strokeWidth={1.1}
 85→          vectorEffect="non-scaling-stroke"
 86→        />
 87→      ))}
 88→      <line
 89→        x1={scene.bounds.minX}
 90→        y1={0}
 91→        x2={scene.bounds.maxX}
 92→        y2={0}
 93→        stroke={DRAWING_GRAPHICS.section.groundStroke}
 94→        strokeWidth={0.8}
 95→        strokeDasharray={DRAWING_GRAPHICS.section.groundDash}
 96→        vectorEffect="non-scaling-stroke"
 97→      />
 98→      <BlueprintAnnotationLayer
 99→        dimensions={scene.dimensions || []}
100→        tags={[...(scene.tags || []), ...(scene.topChordTags || []), ...(scene.webTags || [])]}
101→        className="truss-detail-annotations"
102→      />
103→    </g>
104→  );
105→}
