105→function resolveTagStyle(tag, isRoom) {
106→  const isInformationalMeasurement = (
107→    tag.semanticRole === ANNOTATION_SEMANTIC_ROLES.MEASUREMENT
108→    && tag.trustLevel !== ANNOTATION_TRUST_LEVELS.AUTHORITATIVE
109→  );
110→
111→  if (isRoom) {
112→    return {
113→      textFill: DRAWING_GRAPHICS.annotation.text,
114→      fontWeight: 600,
115→      maskOpacity: 0.92,
116→      leaderStroke: DRAWING_GRAPHICS.annotation.dimensionExtension,
117→      leaderDash: undefined,
118→    };
119→  }
120→
121→  if (isInformationalMeasurement) {
122→    return {
123→      textFill: SHEET_COLORS.textMuted,
124→      fontWeight: 500,
125→      maskOpacity: 0.84,
126→      leaderStroke: SHEET_COLORS.borderMuted,
127→      leaderDash: '6 4',
128→    };
129→  }
130→
131→  return {
132→    textFill: DRAWING_GRAPHICS.annotation.textMuted,
133→    fontWeight: 500,
134→    maskOpacity: 0.92,
135→    leaderStroke: DRAWING_GRAPHICS.annotation.dimensionExtension,
136→    leaderDash: undefined,
137→  };
138→}
