631→function createDetailTag(id, textLines, position, options = {}) {
632→  const lines = (textLines || []).filter(Boolean);
633→  if (!lines.length) return null;
634→
635→  return {
636→    id,
637→    type: 'tag',
638→    trustLevel: options.trustLevel ?? ANNOTATION_TRUST_LEVELS.INFORMATIONAL,
639→    semanticRole: options.semanticRole ?? ANNOTATION_SEMANTIC_ROLES.MEASUREMENT,
640→    sourceType: options.sourceType ?? 'truss_detail',
641→    sourceId: options.sourceId ?? null,
642→    position,
643→    angle: options.angle ?? 0,
644→    textLines: lines,
645→    textAnchor: options.textAnchor ?? 'middle',
646→    priority: options.priority ?? 0,
647→    measurementMeta: Number.isFinite(options.measurementValue)
648→      ? createMeasurementMetadata(options.measurementValue)
649→      : null,
650→    fontSize: options.fontSize ?? DETAIL_TAG_FONT_SIZE,
651→    lineHeight: options.lineHeight ?? DETAIL_TAG_LINE_HEIGHT,
652→    mask: options.mask ?? true,
653→    maskPaddingX: options.maskPaddingX ?? DETAIL_TAG_MASK_PADDING_X,
654→    maskPaddingY: options.maskPaddingY ?? DETAIL_TAG_MASK_PADDING_Y,
